const API_BASE="localhost"===location.hostname||"127.0.0.1"===location.hostname?"http://localhost:3001/api":`${location.origin}/api`;let backendOnline=!1;async function checkBackend(){try{const n=await fetch(`${API_BASE}/health`,{signal:AbortSignal.timeout(5e3)});backendOnline=n.ok}catch{await new Promise(n=>setTimeout(n,3e3));try{const n=await fetch(`${API_BASE}/health`,{signal:AbortSignal.timeout(8e3)});backendOnline=n.ok}catch{backendOnline=!1}}return backendOnline}async function fetchStats(){if(!backendOnline)return null;try{const n=await fetch(`${API_BASE}/stats`);return n.ok?await n.json():null}catch{return null}}async function apiTrackView(n){if(!backendOnline)return null;try{const t=await fetch(`${API_BASE}/projects/${n}/view`,{method:"POST"});return t.ok?await t.json():null}catch{return null}}async function apiToggleLike(n,t){if(!backendOnline)return null;try{const e=await fetch(`${API_BASE}/projects/${n}/like`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:t})});return e.ok?await e.json():null}catch{return null}}async function fetchComments(n="newest"){if(!backendOnline)return null;try{const t=await fetch(`${API_BASE}/comments?sort=${n}`);return t.ok?await t.json():null}catch{return null}}async function postComment(n){if(!backendOnline)return null;try{const t=await fetch(`${API_BASE}/comments`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(n)});if(!t.ok){const n=await t.json();throw new Error(n.error||"Lỗi server")}return await t.json()}catch(n){throw n}}async function apiLikeComment(n){if(!backendOnline)return null;try{const t=await fetch(`${API_BASE}/comments/${n}/like`,{method:"POST"});return t.ok?await t.json():null}catch{return null}}async function postMessage(n){if(!backendOnline)return null;try{return(await fetch(`${API_BASE}/messages`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(n)})).ok}catch{return null}}async function sendChatMessage(n){try{const t=await fetch(`${API_BASE}/chat`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({message:n})});if(!t.ok)throw new Error("Server error");return(await t.json()).reply}catch{return null}}async function adminFetchMessages(n){try{const t=await fetch(`${API_BASE}/messages`,{headers:{"x-admin-token":n}});return t.ok?await t.json():null}catch{return null}}async function adminMarkRead(n,t){try{await fetch(`${API_BASE}/messages/${n}/read`,{method:"PATCH",headers:{"x-admin-token":t}})}catch{}}async function adminDeleteMessage(n,t){try{await fetch(`${API_BASE}/messages/${n}`,{method:"DELETE",headers:{"x-admin-token":t}})}catch{}}async function adminClearAllMessages(n){try{await fetch(`${API_BASE}/messages`,{method:"DELETE",headers:{"x-admin-token":n}})}catch{}}async function adminDeleteComment(n,t){try{await fetch(`${API_BASE}/comments/${n}`,{method:"DELETE",headers:{"x-admin-token":t}})}catch{}}async function adminClearAllComments(n){try{await fetch(`${API_BASE}/comments`,{method:"DELETE",headers:{"x-admin-token":n}})}catch{}}checkBackend().then(n=>{});